const survives = (neighborCount: number): boolean =>
  neighborCount === 2 || neighborCount === 3;

const isReproduced = (neighborCount: number): boolean =>
  neighborCount === 3;

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveCells = new Set(cells.map(cellKey));
  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    candidates.set(cellKey(cell), cell);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [cell[0] + dx, cell[1] + dy];
      candidates.set(cellKey(neighbor), neighbor);
    }
  }
  const result: Cell[] = [];
  for (const [key, cell] of candidates) {
    const count = countLiveNeighbors(cell, liveCells);
    if (liveCells.has(key) ? survives(count) : isReproduced(count)) {
      result.push(cell);
    }
  }
  return result;
};

